package courses

import (
	"encoding/json"
	"log"
	"net/http"
)

type CoursesHandlers struct {
	courses *CoursesService
}



func NewCoursesHandlers(service *CoursesService) *CoursesHandlers {
	return &CoursesHandlers{ courses:service }

}

func (handler *CoursesHandlers)GetCoursesHandler(w http.ResponseWriter, r * http.Request){
	w.Header().Set("Content-Type", "application/json")
    cursor := r.URL.Query().Get("cursor")

	courses, err := handler.courses.GetCourses(r.Context(), cursor)

	if (err != nil){
		log.Printf("GetCourses error: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		w.WriteHeader(http.StatusInternalServerError)
		json.NewEncoder(w).Encode(map[string]string{"error": "InternalServerError"})
		return
	}

	json.NewEncoder(w).Encode(courses)
}

